#include<bits/stdc++.h>
using namespace std;
const int N=205;
int n,a[N],dp[N][N],ans=0;
int main()
{
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
        a[i+n]=a[i];
    }
    for(int len=2;len<=n;len++)
    {
        for(int l=1;l+len<=2*n+1;l++)
        {
            int r=l+len-1;
            for(int k=l;k<r;k++)
            {
                dp[l][r]=max(dp[l][r],dp[l][k]+dp[k+1][r]+a[l]*a[k+1]*a[r+1]);
            }
            ans=max(ans,dp[l][r]);
        }
    }
    cout<<ans;
    return 0;
}
